import type { Tenant, TenantType } from "@/types/bootstrap";
import { createServerFn } from "@tanstack/react-start";
import { z } from "zod";
import { postOrgApiJson } from "../../../server/org-api.server";
import { logServerErrorToRollbar } from "../../../server/rollbar-server.server";

export const createTenant = createServerFn({ method: "POST" })
  .inputValidator(
    z.object({
      name: z.string().trim().min(1),
      tenantType: z.enum(["org", "vendor"]),
    }),
  )
  .handler(async ({ data }) => {
    try {
      return await postOrgApiJson<Tenant>("/tenants", {
        tenant: {
          name: data.name,
          tenant_type: data.tenantType as TenantType,
        },
      });
    } catch (error) {
      logServerErrorToRollbar(
        error instanceof Error ? error : new Error(String(error)),
        { serverFn: "createTenant" },
      );
      throw error;
    }
  });

import { useRef, useState } from "react";
import {
  createFileRoute,
  getRouteApi,
  useNavigate,
  useRouter,
} from "@tanstack/react-router";
import {
  AnedotTypemarkIcon,
  Button,
  buttonVariants,
  Card,
  cn,
  Input,
} from "@workspace/ui";
import { ChevronRight, Image, Plus, X } from "lucide-react";
import { Field, FieldLabel } from "../../../components/ui/field";
import type { TenantType } from "../../../types/bootstrap";
import { createTenant } from "./-organizations";

export const Route = createFileRoute("/_authed/organizations/")({
  component: OrganizationsPage,
});

const authedRouteApi = getRouteApi("/_authed");

type Organization = {
  color: string;
  id: number;
  initial: string;
  name: string;
  orgType: string;
};

type Invite = {
  name: string;
  orgType: string;
  role: string;
  invitedBy: string;
};

const tenantColors = ["#7C3AED", "#0F766E", "#EA580C", "#2563EB", "#BE185D"];

function getInitials(name: string): string {
  const initials = name
    .split(" ")
    .filter(Boolean)
    .slice(0, 2)
    .map((part) => part[0]?.toUpperCase() ?? "")
    .join("");

  return initials || "?";
}

function getTenantColor(index: number): string {
  return tenantColors[index % tenantColors.length] ?? tenantColors[0];
}

function OrganizationCard({
  org,
  onClick,
}: {
  org: Organization;
  onClick: () => void;
}) {
  return (
    <Button
      type="button"
      onClick={onClick}
      variant="card"
      size="card"
      className="flex w-full items-center gap-3.5"
    >
      <div
        className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg font-bold text-white"
        style={{ backgroundColor: org.color }}
      >
        {org.initial}
      </div>
      <div className="flex-1">
        <div className="font-semibold text-foreground text-sm">{org.name}</div>
        <div className="mt-0.5 text-muted-foreground text-xs">
          {org.orgType}
        </div>
      </div>
      <ChevronRight size={16} className="text-muted-foreground" />
    </Button>
  );
}

function InviteCard({
  invite,
  onAccept,
  onDecline,
}: {
  invite: Invite;
  onAccept: () => void;
  onDecline: () => void;
}) {
  return (
    <div className="flex items-center gap-3.5 rounded-xl border-2 border-border bg-card p-4">
      <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-accent font-bold text-muted-foreground">
        {invite.name[0]}
      </div>
      <div className="flex-1">
        <div className="font-semibold text-foreground text-sm">
          {invite.name}
        </div>
        <div className="mt-0.5 text-muted-foreground text-xs">
          Invited by {invite.invitedBy} as {invite.role}
        </div>
      </div>
      <div className="flex gap-1.5">
        <Button variant="outline" size="sm" onClick={onDecline}>
          Decline
        </Button>
        <Button size="sm" onClick={onAccept}>
          Accept
        </Button>
      </div>
    </div>
  );
}

function OrganizationsPage() {
  const navigate = useNavigate();
  const router = useRouter();
  const { user, tenants } = authedRouteApi.useLoaderData();
  const createOrgNameRef = useRef<HTMLInputElement>(null);
  const createOrgToggleRef = useRef<HTMLInputElement>(null);
  const [tenantType, setTenantType] = useState<TenantType>("org");
  const [isCreating, setIsCreating] = useState(false);

  const organizations: Organization[] = tenants.map((tenant, index) => ({
    color: getTenantColor(index),
    id: tenant.id,
    initial: getInitials(tenant.name),
    name: tenant.name,
    orgType: tenant.tenant_type === "org" ? "Organization" : "Vendor",
  }));
  const invites: Invite[] = [];
  const hasContent = organizations.length > 0 || invites.length > 0;
  const currentUserInitial = user.email[0]?.toUpperCase() ?? "?";

  const handleSelectOrg = (_org: Organization) => {
    navigate({ to: "/" });
  };

  const handleAcceptInvite = (_invite: Invite) => {
    navigate({ to: "/" });
  };

  const handleDeclineInvite = (_invite: Invite) => {
    // In the future, this will call the API to decline the invite
  };

  const handleCloseCreateOrg = () => {
    if (createOrgToggleRef.current) {
      createOrgToggleRef.current.checked = false;
    }
    if (createOrgNameRef.current) {
      createOrgNameRef.current.value = "";
    }
    setTenantType("org");
  };

  const handleCreateOrg = async () => {
    const orgName = createOrgNameRef.current?.value.trim() ?? "";

    if (!orgName) return;

    setIsCreating(true);

    try {
      await createTenant({
        data: {
          name: orgName,
          tenantType,
        },
      });
      await router.invalidate();
      handleCloseCreateOrg();
      navigate({ to: "/" });
    } finally {
      setIsCreating(false);
    }
  };

  return (
    <div className="min-h-screen bg-muted font-outfit">
      {/* Top bar */}
      <header className="border-border border-b bg-background/80 backdrop-blur-sm">
        <div className="mx-auto flex h-14 max-w-6xl items-center justify-between px-6">
          <AnedotTypemarkIcon size={100} className="text-secondary-600" />
          <div className="flex h-8 w-8 items-center justify-center rounded-full bg-muted font-semibold text-primary text-sm">
            {currentUserInitial}
          </div>
        </div>
      </header>

      {/* Main content */}
      <main className="mx-auto max-w-lg px-6 py-8">
        <div className="mb-8 text-center">
          <h1 className="font-bold text-2xl text-foreground">
            {hasContent ? "Your organizations" : "Welcome to Anedot"}
          </h1>
          <p className="mt-2 text-muted-foreground text-sm leading-relaxed">
            {hasContent
              ? "Select an organization to continue, or create a new one."
              : "Create an organization to get started, or accept an invitation to join one."}
          </p>
        </div>

        {/* Existing organizations */}
        {organizations.length > 0 && (
          <div className="mb-6 flex flex-col gap-2">
            {organizations.map((org) => (
              <OrganizationCard
                key={org.id}
                org={org}
                onClick={() => handleSelectOrg(org)}
              />
            ))}
          </div>
        )}

        {/* Pending invites */}
        {invites.length > 0 && (
          <div className="mb-6">
            <div className="mb-2.5 font-bold text-muted-foreground text-xs uppercase tracking-wide">
              Pending invitations
            </div>
            <div className="flex flex-col gap-2">
              {invites.map((invite) => (
                <InviteCard
                  key={invite.name}
                  invite={invite}
                  onAccept={() => handleAcceptInvite(invite)}
                  onDecline={() => handleDeclineInvite(invite)}
                />
              ))}
            </div>
          </div>
        )}

        {/* Create organization button / form */}
        <div className="w-full">
          <input
            ref={createOrgToggleRef}
            id="create-org-toggle"
            type="checkbox"
            className="peer sr-only"
          />
          <label
            htmlFor="create-org-toggle"
            className={cn(
              buttonVariants({
                size: "card",
                variant: hasContent ? "dashed" : "secondary",
              }),
              "flex w-full gap-2 peer-checked:hidden",
            )}
          >
            <Plus size={16} /> Create a new organization
          </label>

          <Card className="fade-in slide-in-from-top-1 mt-4 hidden animate-in p-6 peer-checked:block">
            <div className="mb-5 flex items-center justify-between">
              <h3 className="font-bold text-foreground">Create organization</h3>
              <Button
                type="button"
                onClick={handleCloseCreateOrg}
                variant="ghost"
                size="icon-xs"
                aria-label="Close create organization"
                className="text-muted-foreground hover:text-foreground"
              >
                <X size={16} />
              </Button>
            </div>

            <Field className="mb-4">
              <FieldLabel htmlFor="orgName">Organization name</FieldLabel>
              <Input
                ref={createOrgNameRef}
                id="orgName"
                placeholder="e.g. Hope Foundation"
                className="h-10"
              />
            </Field>

            <Field className="mb-4">
              <FieldLabel>Type</FieldLabel>
              <div className="flex flex-wrap gap-1.5">
                {(
                  [
                    { label: "Organization", value: "org" as const },
                    { label: "Vendor", value: "vendor" as const },
                  ] as const
                ).map((option) => (
                  <Button
                    key={option.value}
                    type="button"
                    onClick={() => setTenantType(option.value)}
                    variant="chip"
                    size="chip"
                    aria-pressed={tenantType === option.value}
                  >
                    {option.label}
                  </Button>
                ))}
              </div>
            </Field>

            <Field className="mb-5">
              <FieldLabel>
                Logo{" "}
                <span className="font-normal text-muted-foreground">
                  Optional
                </span>
              </FieldLabel>
              <Button
                type="button"
                variant="upload"
                size="card"
                className="w-full gap-2"
              >
                <Image size={20} /> Upload logo
              </Button>
            </Field>

            <Button
              type="button"
              disabled={isCreating}
              className="w-full"
              onClick={handleCreateOrg}
            >
              {isCreating ? "Creating organization..." : "Create organization"}
            </Button>
          </Card>
        </div>
      </main>
    </div>
  );
}

import { useState } from "react";
import { reportClientError } from "@/lib/report-client-error";
import { getAppBootstrapData } from "@/server/app-bootstrap";
import { useForm } from "@tanstack/react-form";
import {
  createFileRoute,
  Link,
  useNavigate,
  useRouter,
} from "@tanstack/react-router";
import { AnedotTypemarkIcon, Button, Card, cn, Input } from "@workspace/ui";
import { Field, FieldLabel } from "../../../components/ui/field";
import type { TenantType } from "../../../types/bootstrap";
import { createTenant } from "./-organizations";

const tenantTypeOptions: {
  description: string;
  label: string;
  value: TenantType;
}[] = [
  {
    description:
      "For campaigns, donations, and payouts. This is the default for most users.",
    label: "Organization",
    value: "org",
  },
  {
    description: "For partners managing multiple client organizations.",
    label: "Vendor",
    value: "vendor",
  },
];

export const Route = createFileRoute("/_authed/organizations/new")({
  loader: () => getAppBootstrapData(),
  component: NewOrganizationPage,
});

function NewOrganizationPage() {
  const { user } = Route.useLoaderData();
  const navigate = useNavigate();
  const router = useRouter();
  const [formError, setFormError] = useState<string | null>(null);

  const form = useForm({
    defaultValues: {
      name: "",
      tenantType: "org" as TenantType,
    },
    onSubmit: async ({ value }) => {
      setFormError(null);
      try {
        await createTenant({
          data: {
            name: value.name.trim(),
            tenantType: value.tenantType,
          },
        });
        await router.invalidate();
        await navigate({ to: "/" });
      } catch (error) {
        const message =
          "Could not create your organization. Please try again.";
        setFormError(message);
        reportClientError(error, { operation: "createTenant" }, message);
      }
    },
  });

  const currentUserInitial = user.email[0]?.toUpperCase() ?? "?";

  return (
    <div className="min-h-screen bg-muted font-outfit">
      <header className="border-border border-b bg-background/80 backdrop-blur-sm">
        <div className="mx-auto flex h-14 max-w-6xl items-center justify-between px-6">
          <Link to="/">
            <AnedotTypemarkIcon size={100} className="text-secondary-600" />
          </Link>
          <div className="flex h-8 w-8 items-center justify-center rounded-full bg-muted font-semibold text-primary text-sm">
            {currentUserInitial}
          </div>
        </div>
      </header>

      <main className="mx-auto max-w-lg px-6 py-10">
        <div className="mb-8 text-center">
          <h1 className="font-bold text-2xl text-foreground">
            Create your organization
          </h1>
          <p className="mt-2 text-muted-foreground text-sm leading-relaxed">
            An organization is where you run campaigns and manage donations. You
            can add more later.
          </p>
        </div>

        <Card className="p-6">
          <form
            className="space-y-5"
            onSubmit={(e) => {
              e.preventDefault();
              e.stopPropagation();
              form.handleSubmit();
            }}
          >
            <form.Field
              name="name"
              validators={{
                onSubmit: ({ value }) =>
                  !value.trim() ? "Name is required" : undefined,
              }}
              children={(field) => (
                <Field>
                  <FieldLabel htmlFor="organization-name">
                    Organization name
                  </FieldLabel>
                  <Input
                    autoComplete="organization"
                    className="h-10"
                    id="organization-name"
                    name={field.name}
                    onBlur={field.handleBlur}
                    onChange={(e) => field.handleChange(e.target.value)}
                    placeholder="e.g. Hope Foundation"
                    value={field.state.value}
                  />
                </Field>
              )}
            />

            <form.Field
              name="tenantType"
              children={(field) => (
                <Field>
                  <FieldLabel>Type</FieldLabel>
                  <div className="flex flex-col gap-2">
                    {tenantTypeOptions.map((option) => (
                      <button
                        className={cn(
                          "rounded-xl border-2 p-3.5 text-left transition-colors",
                          field.state.value === option.value
                            ? "border-secondary-500 bg-secondary-50"
                            : "border-border bg-card hover:border-muted-foreground/30",
                        )}
                        key={option.value}
                        type="button"
                        onClick={() => field.handleChange(option.value)}
                      >
                        <div className="font-semibold text-foreground text-sm">
                          {option.label}
                        </div>
                        <p className="mt-1 text-muted-foreground text-xs leading-relaxed">
                          {option.description}
                        </p>
                      </button>
                    ))}
                  </div>
                </Field>
              )}
            />

            {formError ? (
              <p className="text-destructive text-sm" role="alert">
                {formError}
              </p>
            ) : null}

            <form.Subscribe
              selector={(state) => [state.canSubmit, state.isSubmitting]}
              children={([canSubmit, isSubmitting]) => (
                <Button
                  className="w-full"
                  disabled={!canSubmit || isSubmitting}
                  type="submit"
                >
                  {isSubmitting
                    ? "Creating organization..."
                    : "Create organization"}
                </Button>
              )}
            />
          </form>
        </Card>

        <p className="mt-6 text-center text-muted-foreground text-sm">
          Already have access to an organization?{" "}
          <Link
            className="font-semibold text-secondary-600 hover:text-secondary-700"
            to="/organizations"
          >
            View your organizations
          </Link>
        </p>
      </main>
    </div>
  );
}

