import { expect, test } from "./test-fixture";

const usersApiPattern = /http:\/\/localhost:3210\/users\/me/;
const tenantsApiPattern = /http:\/\/localhost:3210\/tenants/;

const mockUser = {
  id: 1,
  email: "test@example.com",
  cognito_sub: null,
  created_at: "2024-01-01T00:00:00Z",
  updated_at: "2024-01-01T00:00:00Z",
};

test("creates an organization tenant and returns to the homepage", async ({
  page,
  mockServerRequest,
}) => {
  await mockServerRequest.GET(usersApiPattern, { body: mockUser });
  await mockServerRequest.GET(tenantsApiPattern, { body: [] });

  await page.goto("/organizations/new", { waitUntil: "networkidle" });

  await page.locator("#organization-name").fill("Acme co");

  await page
    .getByRole("button")
    .filter({ has: page.getByText("Organization", { exact: true }) })
    .click();

  const createdTenant = {
    id: 42,
    tenant_type: "org" as const,
    name: "Hope Foundation",
    org_id: "org-42",
    vendor_id: null,
    created_at: "2024-01-01T00:00:00Z",
    updated_at: "2024-01-01T00:00:00Z",
  };

  await mockServerRequest.reset();
  await mockServerRequest.GET(usersApiPattern, { body: mockUser });
  await mockServerRequest.GET(tenantsApiPattern, { body: [createdTenant] });
  await mockServerRequest.POST(tenantsApiPattern, { body: createdTenant });
  await mockServerRequest.GET(
    /http:\/\/localhost:3210\/campaigns\?[^#]*tenant_id=42/,
    { body: [] },
  );

  await page.getByRole("button", { name: "Create organization" }).click();

  await expect(page).toHaveURL(/^http:\/\/localhost:3210\/?$/);
});

test("creates a vendor tenant and returns to the homepage", async ({
  page,
  mockServerRequest,
}) => {
  await mockServerRequest.GET(usersApiPattern, { body: mockUser });
  await mockServerRequest.GET(tenantsApiPattern, { body: [] });

  await page.goto("/organizations/new", { waitUntil: "networkidle" });

  await page.locator("#organization-name").fill("Acme Vendor Co");
  await page
    .getByRole("button")
    .filter({ has: page.getByText("Vendor", { exact: true }) })
    .click();

  const createdTenant = {
    id: 43,
    tenant_type: "vendor" as const,
    name: "Acme Vendor Co",
    org_id: null,
    vendor_id: "ven-43",
    created_at: "2024-01-01T00:00:00Z",
    updated_at: "2024-01-01T00:00:00Z",
  };

  await mockServerRequest.reset();
  await mockServerRequest.GET(usersApiPattern, { body: mockUser });
  await mockServerRequest.GET(tenantsApiPattern, { body: [createdTenant] });
  await mockServerRequest.POST(tenantsApiPattern, { body: createdTenant });
  await mockServerRequest.GET(
    /http:\/\/localhost:3210\/campaigns\?[^#]*tenant_id=43[^#]*vendor_id=43/,
    { body: [] },
  );

  await page.getByRole("button", { name: "Create organization" }).click();

  await expect(page).toHaveURL(/^http:\/\/localhost:3210\/?$/);
});

